<div class="page-header"><div><h2 class="page-title">Creer une relation post / categorie</h2><p class="page-meta">Associez un article a une categorie.</p></div></div><form action="/admin/post-categories"class="card form-card"method="post"><div class="form-field"><label for="post_id">Article</label> <select class="form-select"id="post_id"name="post_id"required><option value="">-- Choisir un article --</option><?php foreach($posts as $post): ?><option value="<?=(int)$post['id']?>">#<?=(int)$post['id']?>-<?=htmlspecialchars($post['title'])?></option><?php endforeach; ?></select></div><div class="form-field"><label for="category_id">Categorie</label> <select class="form-select"id="category_id"name="category_id"required><option value="">-- Choisir une categorie --</option><?php foreach($categories as $category): ?><option value="<?=(int)$category['id']?>">#<?=(int)$category['id']?>-<?=htmlspecialchars($category['name'])?></option><?php endforeach; ?></select></div><button class="btn btn-primary"type="submit">Enregistrer</button> <a class="btn btn-ghost"href="/admin/post-categories">Annuler</a></form>